ALTER TABLE public.purchase_orders DROP CONSTRAINT purchase_orders_status_check;
ALTER TABLE public.purchase_orders ADD CONSTRAINT purchase_orders_status_check CHECK (status = ANY (ARRAY['draft'::text, 'submitted'::text, 'approved'::text, 'ordered'::text, 'partially_received'::text, 'received'::text, 'invoiced'::text, 'cancelled'::text, 'closed'::text]));